export const validateCartAddition = (cart, nuevoProducto, modoEntrega) => {
    if (cart.length > 0) {
        // Comparamos IDs de MongoDB
        const localIdCarrito = cart[0].localId;
        const localIdNuevo = nuevoProducto.localId;
        
        if (localIdCarrito !== localIdNuevo) {
            return { 
                valid: false, 
                msg: "Solo puedes pedir productos de un mismo local." 
            };
        }
    }
    // ... resto de validaciones de peso y cantidad
    return { valid: true };
};
